PhiDavydychev[L_Integer, x_, y_] := Module[{lambda, rho}, lambda = Sqrt[(1 - x - y)^2 - 4 x y]; rho = 2/(1 - x - y + lambda); -(1/(L! lambda)) Sum[((-1)^j j! Log[y/x]^(2 L - j))/((j - L)! (2 L - j)!) (PolyLog[j, -1/(rho x)] - PolyLog[j, -rho y]), {j, L, 2 L}]];

(* 4-mass box ladder: I_box^(L)(s, t, p1sq, p2sq, p3sq, p4sq) *)
IBox[L_Integer, s_, t_, p1sq_, p2sq_, p3sq_, p4sq_] := PhiDavydychev[L, p1sq p3sq/(s t), p2sq p4sq/(s t)] / (s t^L)

PhiDavydychev[L_Integer, x_, y_] := Module[{lambda, rho}, lambda = Sqrt[(1 - x - y)^2 - 4 x y]; rho = 2/(1 - x - y + lambda); -(1/(L! lambda)) Sum[((-1)^j j! Log[y/x]^(2 L - j))/((j - L)! (2 L - j)!) (PolyLog[j, -1/(rho x)] - PolyLog[j, -rho y]), {j, L, 2 L}]];

BDCoeff[i_, j_, M_, N_] := (M - N - 1 + i + j)!/((i - 1)! (j - 1)! (M - j)! (N - i)!);
(* Basso-Dixon fishnet: I_{M,N}(s, t, p1sq, p2sq, p3sq, p4sq) *)
IBassoDixon[M_Integer, N_Integer, s_, t_, p1sq_, p2sq_, p3sq_, p4sq_] := Det[Table[BDCoeff[i, j, M, N] PhiDavydychev[M - N - 1 + i + j, p1sq p3sq/(s t), p2sq p4sq/(s t)], {i, N}, {j, N}]] / (s t^M)

PhiDavydychev[L_Integer, x_, y_] := Module[{lambda, rho}, lambda = Sqrt[(1 - x - y)^2 - 4 x y]; rho = 2/(1 - x - y + lambda); -(1/(L! lambda)) Sum[((-1)^j j! Log[y/x]^(2 L - j))/((j - L)! (2 L - j)!) (PolyLog[j, -1/(rho x)] - PolyLog[j, -rho y]), {j, L, 2 L}]];

(* Generalised ladder (fan): I_fan^(L)(p1sq, p2sq, p3sq) *)
IFan[L_Integer, p1sq_, p2sq_, p3sq_] := PhiDavydychev[L, p1sq/p3sq, p2sq/p3sq] / p3sq^L

