(* Triangle ladder: I_triangle^(L)(p1sq, p2sq, p3sq) *)
ITriangle[L_Integer, p1sq_, p2sq_, p3sq_] := PhiDavydychev[L, p1sq/p3sq, p2sq/p3sq] / p3sq^L
